		EventID:   "evt-" + randomProgressID(),
		WorkerID:  runtime.WorkerID,
		ProjectID: runtime.ProjectRoot,
		BeadID:    candidate.ID,
		Phase:     "loop.active",
		Heartbeat: true,
		TS:        now().UTC(),
